std::array<bool, kFeatureCount> g_enabled {};
int g_category = 0;
int g_page = 0;
float g_timeWarp = 1.0f;
PlayLayer* g_playLayer = nullptr;

size_t featureCountForCategory(int category) {
  size_t count = 0;
  for (auto const& feature : kFeatures) {
    if (feature.category == category) {
      ++count;
    }
  }
  return count;
}

size_t absoluteFeatureIndex(int category, int page, int row) {
  size_t wanted = static_cast<size_t>(std::max(0, page)) * kRowsPerPage + static_cast<size_t>(row);
  size_t seen = 0;
  for (size_t i = 0; i < kFeatures.size(); ++i) {
    if (kFeatures[i].category != category) {
      continue;
    }
    if (seen == wanted) {
      return i;
    }
    ++seen;
  }
  return kFeatures.size();
}

int maxPageForCategory(int category) {
  auto count = featureCountForCategory(category);
  if (count == 0) {
    return 0;
  }
  return static_cast<int>((count - 1) / kRowsPerPage);
}

void clampNavigation() {
  g_category = std::clamp(g_category, 0, static_cast<int>(kCategoryCount) - 1);
  g_page = std::clamp(g_page, 0, maxPageForCategory(g_category));
}

char const* actionName(HubAction action) {
  switch (action) {
    case HubAction::ToggleNoDeath: return "No Death";
    case HubAction::TogglePractice: return "Practice";
    case HubAction::ToggleHideP1: return "Hide P1";
    case HubAction::ToggleAttempts: return "Attempts";
    case HubAction::ToggleProgress: return "Progress";
    case HubAction::ToggleInfo: return "Info";
    case HubAction::ToggleGround: return "Ground";
    case HubAction::ToggleMG: return "MG";
    case HubAction::ToggleBGFX: return "BG FX";
    case HubAction::SpeedHalf: return "Speed 0.50x";
    case HubAction::SpeedNormal: return "Speed 1.00x";
    case HubAction::SpeedFast: return "Speed 1.50x";
    case HubAction::SpeedDouble: return "Speed 2.00x";
    case HubAction::Restart: return "Restart";
    case HubAction::ClearCheckpoints: return "Clear CP";
    case HubAction::ReleaseInputs: return "Release";
    case HubAction::ToggleGeneric: return "Toggle";
  }
  return "Toggle";
}

bool isToggleAction(HubAction action) {
  switch (action) {
    case HubAction::SpeedHalf:
    case HubAction::SpeedNormal:
    case HubAction::SpeedFast:
    case HubAction::SpeedDouble:
    case HubAction::Restart:
    case HubAction::ClearCheckpoints:
    case HubAction::ReleaseInputs:
      return false;
    default:
      return true;
  }
}

void applyPersistentFeatures(PlayLayer* layer) {
  if (!layer) {
    return;
  }

  auto player = layer->m_player1;
  if (player) {
    player->setVisible(!g_enabled[2]);
  }

  if (layer->m_isIgnoreDamageEnabled != g_enabled[0]) {
    layer->toggleIgnoreDamage(g_enabled[0]);
  }

  layer->updateTimeWarp(g_timeWarp);
}

void runAction(size_t index) {
  if (index >= kFeatures.size()) {
    return;
  }

  auto const action = kFeatures[index].action;
  if (isToggleAction(action)) {
    g_enabled[index] = !g_enabled[index];
  }

  auto layer = g_playLayer ? g_playLayer : PlayLayer::get();
  switch (action) {
    case HubAction::ToggleNoDeath:
    case HubAction::ToggleHideP1:
      applyPersistentFeatures(layer);
      break;
    case HubAction::TogglePractice:
      if (layer) layer->togglePracticeMode(g_enabled[index]);
      break;
    case HubAction::ToggleAttempts:
      if (layer) layer->toggleHideAttempts(!g_enabled[index]);
      break;
    case HubAction::ToggleProgress:
      if (layer) layer->toggleProgressbar();
      break;
    case HubAction::ToggleInfo:
      if (layer) layer->toggleInfoLabel();
      break;
    case HubAction::ToggleGround:
      if (layer) layer->toggleGroundVisibility(g_enabled[index]);
      break;
    case HubAction::ToggleMG:
      if (layer) layer->toggleMGVisibility(g_enabled[index]);
      break;
    case HubAction::ToggleBGFX:
      if (layer) layer->toggleBGEffectVisibility(g_enabled[index]);
      break;
    case HubAction::SpeedHalf:
      g_timeWarp = 0.5f;
      if (layer) layer->updateTimeWarp(g_timeWarp);
      break;
    case HubAction::SpeedNormal:
      g_timeWarp = 1.0f;
      if (layer) layer->updateTimeWarp(g_timeWarp);
      break;
    case HubAction::SpeedFast:
      g_timeWarp = 1.5f;
      if (layer) layer->updateTimeWarp(g_timeWarp);
      break;
    case HubAction::SpeedDouble:
      g_timeWarp = 2.0f;
      if (layer) layer->updateTimeWarp(g_timeWarp);
      break;
    case HubAction::Restart:
      if (layer) layer->resetLevelFromStart();
      break;
    case HubAction::ClearCheckpoints:
      if (layer) layer->removeAllCheckpoints();
      break;
    case HubAction::ReleaseInputs:
      if (layer && layer->m_player1) layer->m_player1->releaseAllButtons();
      break;
    case HubAction::ToggleGeneric:
      break;
  }
}

CCLabelBMFont* makeLabel(char const* text, float scale, CCPoint position, CCNode* parent) {
  auto label = CCLabelBMFont::create(text, "bigFont.fnt");
  label->setScale(scale);
  label->setPosition(position);
  parent->addChild(label);
  return label;
}

class EmirHubPopup final : public Popup<> {
protected:
  CCLayer* m_contentLayer = nullptr;
  CCLabelBMFont* m_statusLabel = nullptr;

  bool setup() override {
    this->setTitle("Emir Hub XXL");

    m_contentLayer = CCLayer::create();
    m_mainLayer->addChild(m_contentLayer);

    auto subtitle = CCLabelBMFont::create("Huge Mod Menu - 2304 entries", "goldFont.fnt");
    subtitle->setScale(0.42f);
    subtitle->setPosition({210.0f, 250.0f});
    m_mainLayer->addChild(subtitle);

    auto categoryMenu = CCMenu::create();
    categoryMenu->setPosition({0.0f, 0.0f});
    m_mainLayer->addChild(categoryMenu);

    for (size_t i = 0; i < kCategories.size(); ++i) {
      auto label = CCLabelBMFont::create(kCategories[i].name, "bigFont.fnt");
      label->setScale(0.32f);
      auto item = CCMenuItemSpriteExtra::create(label, this, menu_selector(EmirHubPopup::onCategory));
      item->setTag(static_cast<int>(i));
      item->setPosition({43.0f + static_cast<float>(i % 4) * 83.0f, 224.0f - static_cast<float>(i / 4) * 21.0f});
      categoryMenu->addChild(item);
    }

    auto navMenu = CCMenu::create();
    navMenu->setPosition({0.0f, 0.0f});
    m_mainLayer->addChild(navMenu);

    auto prevLabel = CCLabelBMFont::create("< Prev", "bigFont.fnt");
    prevLabel->setScale(0.44f);
    auto prevItem = CCMenuItemSpriteExtra::create(prevLabel, this, menu_selector(EmirHubPopup::onPrevPage));
    prevItem->setPosition({52.0f, 24.0f});
    navMenu->addChild(prevItem);

    auto nextLabel = CCLabelBMFont::create("Next >", "bigFont.fnt");
    nextLabel->setScale(0.44f);
    auto nextItem = CCMenuItemSpriteExtra::create(nextLabel, this, menu_selector(EmirHubPopup::onNextPage));
    nextItem->setPosition({368.0f, 24.0f});
    navMenu->addChild(nextItem);

    m_statusLabel = CCLabelBMFont::create("", "chatFont.fnt");
    m_statusLabel->setScale(0.52f);
    m_statusLabel->setAnchorPoint({0.5f, 0.5f});
    m_statusLabel->setPosition({210.0f, 45.0f});
    m_mainLayer->addChild(m_statusLabel);

    refreshContent();
    return true;
  }

  void refreshContent() {
    clampNavigation();
    m_contentLayer->removeAllChildrenWithCleanup(true);

    auto title = fmt::format("{} | page {}/{}", kCategories[g_category].name, g_page + 1, maxPageForCategory(g_category) + 1);
    makeLabel(title.c_str(), 0.45f, {210.0f, 181.0f}, m_contentLayer);

    auto description = CCLabelBMFont::create(kCategories[g_category].description, "chatFont.fnt");
    description->setScale(0.45f);
    description->setPosition({210.0f, 162.0f});
    m_contentLayer->addChild(description);

    auto featureMenu = CCMenu::create();
    featureMenu->setPosition({0.0f, 0.0f});
    m_contentLayer->addChild(featureMenu);

    for (size_t row = 0; row < kRowsPerPage; ++row) {
      auto index = absoluteFeatureIndex(g_category, g_page, static_cast<int>(row));
      if (index >= kFeatures.size()) {
        continue;
      }

      auto const& feature = kFeatures[index];
      auto enabled = g_enabled[index];
      auto prefix = enabled ? "[ON]" : (isToggleAction(feature.action) ? "[--]" : "[>>]");
      auto text = fmt::format("{} {}", prefix, feature.title);
      auto label = CCLabelBMFont::create(text.c_str(), enabled ? "goldFont.fnt" : "bigFont.fnt");
      label->setScale(0.28f);
      auto item = CCMenuItemSpriteExtra::create(label, this, menu_selector(EmirHubPopup::onFeature));
      item->setTag(static_cast<int>(index));
      auto col = static_cast<float>(row / 6);
      auto localRow = static_cast<float>(row % 6);
      item->setPosition({112.0f + col * 202.0f, 139.0f - localRow * 17.0f});
      featureMenu->addChild(item);

      auto desc = CCLabelBMFont::create(feature.description, "chatFont.fnt");
      desc->setScale(0.23f);
      desc->setAnchorPoint({0.0f, 0.5f});
      desc->setPosition({18.0f + col * 202.0f, 130.5f - localRow * 17.0f});
      desc->setOpacity(130);
      m_contentLayer->addChild(desc);
    }

    auto status = fmt::format("{} features in category | total {} | speed {:.2f}x", featureCountForCategory(g_category), kFeatureCount, g_timeWarp);
    m_statusLabel->setString(status.c_str());
  }

  void onFeature(CCObject* sender) {
    auto item = static_cast<CCNode*>(sender);
    auto index = static_cast<size_t>(item->getTag());
    runAction(index);
    refreshContent();
  }

  void onCategory(CCObject* sender) {
    auto item = static_cast<CCNode*>(sender);
    g_category = item->getTag();
    g_page = 0;
    refreshContent();
  }

  void onPrevPage(CCObject*) {
    --g_page;
    refreshContent();
  }

  void onNextPage(CCObject*) {
    ++g_page;
    refreshContent();
  }

public:
  static EmirHubPopup* create() {
    auto ret = new EmirHubPopup();
    if (ret && ret->initAnchored(420.0f, 280.0f)) {
      ret->autorelease();
      return ret;
    }
    delete ret;
    return nullptr;
  }
};
